class Solution(object):
    def summaryRanges(self, nums):
        """
        :type nums: List[int]
        :rtype: List[str]
        """
        if not nums:
            return []

        res = []
        start = nums[0]

        for i in range(1, len(nums)):
            # If difference between current number and start number is 1
            # Then it's part of the current range
            if nums[i] - nums[i-1] == 1:
                continue
            else:
                # If difference is more than 1, it's the end of the previous range
                if start != nums[i-1]:
                    res.append(str(start) + "->" + str(nums[i-1]))
                else:
                    res.append(str(start))

                # Start a new range
                start = nums[i]

        # Last range
        if start != nums[-1]:
            res.append(str(start) + "->" + str(nums[-1]))
        else:
            res.append(str(start))

        return res

