class Solution(object):
    def firstMissingPositive(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        if not nums:
            return 1

        n = len(nums)

        # Step 1: Mark elements as negative if they are out of bound
        for i in range(n):
            if nums[i] <= 0 or nums[i] > n:
                nums[i] = 1

        # Step 2: Use the absolute value of the nums[i] as index and change the sign of nums[nums[i]] to negative
        # If nums[i] is not positive, then it's a duplicate
        for i in range(n):
            a = abs(nums[i])
            if nums[a-1] > 0:
                nums[a-1] = -abs(nums[a-1])

        # Step 3: Find the first positive number from the start, which is the smallest missing positive integer
        for i in range(n):
            if nums[i] > 0:
                return i+1

        return n+1

