from typing import List

class Solution:
    def maxNumber(self, nums1: List[int], nums2: List[int], k: int) -> List[int]:
        def pick_max(nums, k):
            drop = len(nums) - k
            out = []
            for num in nums:
                while drop and out and out[-1] < num:
                    out.pop()
                    drop -= 1
                out.append(num)
            return out

        def merge(a, b):
            ans = []
            while a or b:
                bigger = a if a > b else b
                ans.append(bigger[0])
                bigger.pop(0)
            return ans

        def get_max_array(nums):
            if len(nums) == 1:
                return nums
            nums1, nums2 = map(list, (nums[:len(nums)//2], nums[len(nums)//2:]))
            a = get_max_array(nums1)
            b = get_max_array(nums2)
            return max(merge(a, b), key=lambda x: x * (len(nums) - len(x)))

        return max(map(lambda x: pick_max(nums1 + nums2, k), get_max_array(nums1 + nums2)), key=len)

