class Solution(object):
    def checkPerfectNumber(self, num):
        """
        :type num: int
        :rtype: bool
        """
        if num <= 1:
            return False

        divisors = [1]
        for potential_divisor in range(2, int(num**0.5) + 1):
            if num % potential_divisor == 0:
                if potential_divisor * potential_divisor == num:
                    divisors.append(potential_divisor)
                else:
                    divisors.append(potential_divisor)
                    divisors.append(num // potential_divisor)

        if sum(divisors) == num:
            return True
        else:
            return False

