    def fib(self, n):
        """
        :type n: int
        :rtype: int
        """
        if n <= 0:
            return 0
        elif n == 1:
            return 1

        # Initialize the dp array with the first two Fibonacci numbers
        dp = [0, 1]

        # Fill the rest of the dp array
        for i in range(2, n + 1):
            dp.append(dp[i - 1] + dp[i - 2])

