class Solution(object):
    def countNodes(self, root):
        """
        :type root: TreeNode
        :rtype: int
        """
        if not root:
            return 0

        # Get the height of the tree
        height = 0
        node = root
        while node:
            height += 1
            node = node.left

        # Calculate the number of nodes
        if height == 0:
            return 1
        else:
            left_height = 0
            left_node = root
            while left_node:
                left_height += 1
                left_node = left_node.left

            if left_height == height - 1:
                return 2**height - 1
            else:
                return 2**(height - 1) - 1 + self.countNodes(root.left)

