import bisect

class Node:
    def __init__(self):
        self.count = 0
        self.left = None
        self.right = None

class SegmentTree:
    def __init__(self, nums):
        self.root = self.build_tree(nums, 0, len(nums) - 1)

    def build_tree(self, nums, start, end):
        if start > end:
            return None

        mid = (start + end) // 2
        node = Node()
        node.left = self.build_tree(nums, start, mid)
        node.right = self.build_tree(nums, mid + 1, end)

        node.count = node.left.count + node.right.count

        return node

    def update(self, index, value):
        self.root = self.update_value(self.root, index, value)

    def update_value(self, node, index, value):
        if node is None:
            return None

        if node.left is None:
            if node.right is None:
                return Node(value)
            else:
                return Node(node.right.count + value)
        else:
            if node.left.count > index:
                return self.update_value(node.left, index, value)
            else:
                return self.update_value(node.right, index - node.left.count - 1, value)

    def query(self, start, end):
        return self.query_range(self.root, start, end)

    def query_range(self, node, start, end):
        if node is None:
            return 0

        if start > end:
            return 0

        if node.left is None:
            return node.count - self.query_range(node.right, end)
        elif node.right is None:
            return self.query_range(node.left, start, node.left.count - 1)

        return node.left.count + node.right.count - self.query_range(node.right, end) - self.query_range(node.left, start, node.left.count - 1)

class Solution:
    def countRangeSum(self, nums, lower, upper):
        prefix_sum = [0]
        for num in nums:
            prefix_sum.append(prefix_sum[-1] + num)

        segment_tree = SegmentTree(prefix_sum)

        count = 0
        for i in range(len(prefix_sum)):
            segment_tree.update(i, 1)

            left_bound = bisect.bisect_left(prefix_sum, prefix_sum[i] - lower)
            right_bound = bisect.bisect_right(prefix_sum, prefix_sum[i] - upper)

            count += max(0, right_bound - left_bound)

            segment_tree.update(i, -1)

        return count

