class DSU:
    def __init__(self, grid):
        self.parent = list(range(len(grid)))
        self.rank = [0] * len(grid)
        self.max_size = 0
        self.total_size = 0
        self.build(grid)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        xr = self.find(x)
        yr = self.find(y)
        if xr != yr:
            if self.rank[xr] < self.rank[yr]:
                self.parent[xr] = yr
            elif self.rank[xr] > self.rank[yr]:
                self.parent[yr] = xr
            else:
                self.parent[yr] = xr
                self.rank[xr] += 1
            self.max_size = max(self.max_size, self.total_size)
            self.total_size -= self.size(xr)

    def size(self, x):
        return len(self.neighbors(x))

    def neighbors(self, x):
        res = []
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, x + dy
            if 0 <= nx < len(self.parent) and 0 <= ny < len(self.parent) and self.parent[nx] != ny:
                res.append(nx)
        return res

    def build(self, grid):
        for i in range(len(grid)):
            for j in range(len(grid[i])):
                if grid[i][j] == 1:
                    self.total_size += 1
                    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                        nx, ny = i + dx, j + dy
                        if 0 <= nx < len(grid) and 0 <= ny < len(grid) and grid[nx][ny] == 1:
                            self.union(i * len(grid) + j, nx * len(grid) + ny)

    def count(self):
        return self.max_size


