class Solution(object):
    def zigzagLevelOrder(self, root):
        """
        :type root: TreeNode
        :rtype: List[List[int]]
        """
        if not root:
            return []

        result, current_level, next_level = [], deque([root]), deque()
        left_to_right = True

        while current_level:
            node = current_level.pop()
            if left_to_right:
                result.append([node.val])
            else:
                result.append([node.val])[::-1]

            if left_to_right:
                if node.left:
                    next_level.append(node.left)
                if node.right:
                    next_level.append(node.right)
            else:
                if node.right:
                    next_level.appendleft(node.right)
                if node.left:
                    next_level.appendleft(node.left)

