            return []

        window = deque()
        result = []

        for i in range(len(nums)):
            # Add the new element to the window
            window.append(nums[i])

            # Slide the window if it's full
            if len(window) == k:
                median = self.find_median(window)
                result.append(median)
                # Remove the first element from the window
                window.popleft()

        # Add the last window if it's not full
        if window:
            median = self.find_median(window)
            result.append(median)

        return result

