class FenwickTree(object):
    def __init__(self, n):
        self.size = n
        self.tree = [0] * (n + 1)

    def update(self, i, delta=1):
        while i <= self.size:
            self.tree[i] += delta
            i += i & -i

    def query(self, i):
        res = 0
        while i > 0:
            res += self.tree[i]
            i -= i & -i
        return res

    def range_query(self, i, j):
        return self.query(j) - self.query(i - 1)

class Solution(object):
    def reversePairs(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        nums = [0] + nums
        index = {}
        for i in range(n):
            index[nums[i]] = i + 1

        nums = sorted([(index.get(x), x) for x in nums])
        tree = FenwickTree(n)
        res = 0
        for i, (j, x) in enumerate(nums):
            res += i - tree.range_query(j)
            tree.update(j)
        return res

