    def numTrees(self, n):
        """
        :type n: int
        :rtype: int
        """
        dp = [[0 for _ in range(n+1)] for _ in range(n+1)]

        # For single node, there is 1 unique BST
        for i in range(1, n+1):
            dp[i][i] = 1

        # For 2 nodes, there are 2 unique BSTs
        for i in range(1, n):
            dp[i][i+1] = 2

        # Fill up the dp table
        for length in range(3, n+1):
            for start in range(1, n-length+2):
                end = start + length - 1
                for root in range(start, end+1):
                    left_subtrees = dp[start][root-1]
                    right_subtrees = dp[root+1][end]
                    total = 0
                    for left in range(1, root+1):
                        for right in range(root+1, end+1):
