class Solution(object):
    def minStickersToSpellWord(self, stickers, target):
        """
        :type stickers: List[str]
        :type target: str
        :rtype: int
        """
        from collections import Counter
        from functools import lru_cache

        # Helper function to calculate the count of each character in the target string
        def count_chars(s):
            return [Counter(s) for s in stickers]

        # Helper function to calculate the number of combinations
        def count_combinations(target, counts, stickers_counts):
            if target == '#':
                return 1
            if target[0] == '{':
                for i, count in enumerate(stickers_counts):
                    if count[target[1]] > 0:
                        count[target[1]] -= 1
                        yield from count_combinations(target[2:], counts, [count] + stickers_counts[:i] + stickers_counts[i+1:])
                        count[target[1]] += 1
            else:
                yield from count_combinations(target[1:], counts, stickers_counts)

        # Calculate the counts of each character in the target string
        counts = count_chars(target)
        # Count the total number of combinations
        total_combinations = sum(sum(c.values()) for c in counts)
        # Use a cache to avoid duplicate calculations
        @lru_cache(None)
        def dp(target):
            if '#' not in target:
                return '#'
            for counts in counts:
                if '#' in counts:
                    counts['#'] -= 1
                    yield from count_combinations(target, counts, list(counts.items()))
                    counts['#'] += 1

        # Return the minimum number of stickers to spell the target string
        return next((i for i, dp_result in enumerate(dp(target)) if dp_result == '#'), -1)

