from collections import deque

class Solution:
    def slidingPuzzle(self, board):
        def neighbors(node):
            zero = node.index(0)
            for direction in ((0, -1), (0, 1), (-1, 0), (1, 0)):
                zero_next_row, zero_next_col = zero / 3 + direction[0], zero % 3 + direction[1]
                if 0 <= zero_next_row < 2 and 0 <= zero_next_col < 3:
                    node_next = list(node)
                    node_next[zero], node_next[zero_next_row * 3 + zero_next_col] = node_next[zero_next_row * 3 + zero_next_col], node_next[zero]
                    yield node_next

        start = tuple(sum(board, []))
        end = (1, 2, 3, 4, 5)
        if start != end:
            return -1

        step = 0
        visited = {start}
        queue = deque([(start, step)])

        while queue:
            node, step = queue.popleft()
            if node == end:
                return step
            for next_node in neighbors(node):
                if next_node not in visited:
                    visited.add(next_node)
                    queue.append((next_node, step + 1))

        return -1

