    def isIsomorphic(self, s, t):
        """
        :type s: str
        :type t: str
        :rtype: bool
        """
        # If both strings are empty, they are isomorphic
        if not s and not t:
            return True

        # If the lengths of the strings are not equal, they cannot be isomorphic
        if len(s) != len(t):
            return False

        # Create a dictionary to store mappings
        s_to_t = {}
        t_to_s = {}

        for char_s, char_t in zip(s, t):
            # If the character is already in the dictionary, check if the mapping is correct
            if char_s in s_to_t and s_to_t[char_s] != char_t:
                return False
            if char_t in t_to_s and t_to_s[char_t] != char_s:
                return False

            # If the character is not in the dictionary, add it
            s_to_t[char_s] = char_t
            t_to_s[char_t] = char_s

        # If we reached here, the strings are isomorphic
        return True

