class Solution(object):
    def countOfAtoms(self, formula):
        """
        :type formula: str
        :rtype: str
        """
        stack = []
        i = 0
        while i < len(formula):
            if formula[i] == '(':
                stack.append(i)
            elif formula[i] == ')':
                start = stack.pop()
                multi = int(formula[i - 1:i] if i > 0 else 1)
                i += 1
                j = i
                while j < len(formula) and formula[j].isdigit():
                    j += 1
                multi *= int(formula[i:j] if j > i else 1)
                self.update(stack[-1], Counter(formula[start + 1:i]), multi)
                i = j
            else:
                j = i + 1
                while j < len(formula) and formula[j].isdigit():
                    j += 1
                multi = int(formula[i:j] if j > i else 1)
                self.update(stack[-1], Counter(formula[i:j]), multi)
                i = j
        atoms = self.getCounts(stack[0])
        return ''.join(atom + str(count) if count > 1 else atom for atom, count in sorted(atoms.items()))

    def update(self, counts, atom_counts, multi):
        for atom, count in atom_counts.items():
            counts[atom] += count * multi

