    def solveSudoku(self, board):
        """
        :type board: List[List[str]]
        :rtype: None Do not return anything, modify board in-place instead.
        """
        def is_valid(board, row, col, num):
            # check in the row
            for x in range(9):
                if board[row][x] == num:
                    return False

            # check in the column
            for x in range(9):
                if board[x][col] == num:
                    return False

            # check in the 3x3 box
            start_row, start_col = row - row%3, col - col%3
            for i in range(3):
                for j in range(3):
                    if board[i + start_row][j + start_col] == num:
                        return False
            return True

        def solve(board):
            for i in range(9):
                for j in range(9):
                    if board[i][j] == ".":
                        for num in "123456789":
                            if is_valid(board, i, j, num):
                                board[i][j] = num  # try this number

                                # recursive call
                                if solve(board):
                                    return True

                                # if not success, backtrack
                                board[i][j] = "."
                        return False  # backtrack
            return True

        solve(board)

