class Solution(object):
    def isScramble(self, s1, s2):
        """
        :type s1: str
        :type s2: str
        :rtype: bool
        """
        if sorted(s1) != sorted(s2):
            return False

        memo = {}

        def dp(s1, s2):
            if (s1, s2) in memo:
                return memo[(s1, s2)]

            if s1 == s2:
                memo[(s1, s2)] = True
                return True

            length = len(s1)
            for i in range(1, length):
                if (dp(s1[:i], s2[:i]) and dp(s1[i:], s2[i:])) or (dp(s1[:i], s2[-i:]) and dp(s1[i:], s2[:-i])):
                    memo[(s1, s2)] = True
                    return True

            memo[(s1, s2)] = False
            return False

        return dp(s1, s2)

