class Solution(object):
    def simplifyPath(self, path):
        """
        :type path: str
        :rtype: str
        """
        stack = []
        for part in path.split("/"):
            if part == "..":
                # go up one level
                if stack:
                    stack.pop()
            elif part == "." or not part:
                # stay on the same level
                continue
            elif part.find(".") != -1:
                # it's a directory
                stack.append(part)

        # join all directories to form the final path
        return "/" + "/".join(stack)

