        :type board: List[List[str]]
        :type words: List[str]
        :rtype: List[str]
        """
        trie = {}
        for word in words:
            node = trie
            for letter in word:
                node = node.setdefault(letter, {})
            node['#'] = word
        self.res = []
        self.board = board
        self.visited = [[False]*len(self.board[0]) for _ in range(len(self.board))]
        for i in range(len(self.board)):
            for j in range(len(self.board[0])):
                self.dfs(i, j, trie)
        return self.res

    def dfs(self, i, j, trie):
        letter = self.board[i][j]
        currentNode = trie.get(letter)
        matchWord = ''
        # If there's no such letter on board, just return
        if currentNode is None:
            return
        # mark as visited
        self.visited[i][j] = True
        matchWord += letter
        # check if this word is a match
        if '#' in currentNode:
            self.res.append(currentNode['#'])
        # check its neighbours
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            x, y = i + dx, j + dy
            if 0 <= x < len(self.board) and 0 <= y < len(self.board[0]) and not self.visited[x][y]:
                self.dfs(x, y, currentNode)
        # un-mark and backtrack
        self.visited[i][j] = False

